import React from 'react';
import ProductCard from './ProductCard';

const ProductList: React.FC = () => {
  const products = [
    { id: 1, name: 'Carrot', price: 2.5, image: 'https://images.unsplash.com/photo-1582515073490-dc7c7f3d8f1e?w=400' },
    { id: 2, name: 'Broccoli', price: 3.0, image: 'https://images.unsplash.com/photo-1604908177527-1b6a8d0b42b2?w=400' },
    { id: 3, name: 'Tomato', price: 1.8, image: 'https://images.unsplash.com/photo-1571689936029-4a3e4f3d7b3b?w=400' }
  ];

  return (
    <div className="container mx-auto px-4 py-6">
      <h1 className="text-3xl font-bold mb-6">Our Fresh Vegetables</h1>
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
        {products.map(product => (
          <ProductCard key={product.id} product={product} />
        ))}
      </div>
    </div>
  );
};

export default ProductList;

